"""Happy-path tests for GET /health."""

import pytest
from fastapi.testclient import TestClient

from app.main import app


@pytest.fixture(scope="module")
def client() -> TestClient:
    return TestClient(app)


def test_health_status_ok(client: TestClient) -> None:
    response = client.get("/health")
    assert response.status_code == 200


def test_health_response_fields(client: TestClient) -> None:
    body = client.get("/health").json()
    assert body["status"] == "ok"


def test_health_version_present(client: TestClient) -> None:
    body = client.get("/health").json()
    assert "version" in body
    assert body["version"] == "1.0.0"


def test_health_content_type(client: TestClient) -> None:
    response = client.get("/health")
    assert response.headers["content-type"].startswith("application/json")

"""Happy-path tests for GET /api/authors."""

import pytest
from fastapi.testclient import TestClient

from app.main import app

_EXPECTED_SLUGS = {"austen", "dickens", "poe"}
_EXPECTED_FIELDS = {"id", "name", "slug", "has_style_profile", "n_documents"}


@pytest.fixture(scope="module")
def client() -> TestClient:
    return TestClient(app)


@pytest.fixture(scope="module")
def authors(client: TestClient) -> list[dict]:
    return client.get("/api/authors").json()


def test_authors_status_ok(client: TestClient) -> None:
    response = client.get("/api/authors")
    assert response.status_code == 200


def test_authors_returns_three(authors: list[dict]) -> None:
    assert len(authors) == 3


def test_authors_slugs(authors: list[dict]) -> None:
    assert {a["slug"] for a in authors} == _EXPECTED_SLUGS


def test_authors_schema_fields(authors: list[dict]) -> None:
    for author in authors:
        assert set(author.keys()) == _EXPECTED_FIELDS


def test_authors_has_style_profile_false(authors: list[dict]) -> None:
    for author in authors:
        assert author["has_style_profile"] is False


def test_authors_n_documents_positive(authors: list[dict]) -> None:
    for author in authors:
        assert author["n_documents"] > 0


def test_authors_content_type(client: TestClient) -> None:
    response = client.get("/api/authors")
    assert response.headers["content-type"].startswith("application/json")

